### HTTPException

Raise HTTP errors using `HTTPException`:

```python
from fastapi import FastAPI, HTTPException

app = FastAPI()

items = {1: "Item 1", 2: "Item 2"}

@app.get("/items/{item_id}")
async def read_item(item_id: int):
    if item_id not in items:
        raise HTTPException(status_code=404, detail="Item not found")
    return {"item": items[item_id]}
```

### Custom Status Codes and Details

```python
from fastapi import HTTPException

@app.post("/users/")
async def create_user(user: User):
    if user_exists(user.email):
        raise HTTPException(
            status_code=409,
            detail="User with this email already exists",
            headers={"X-Error": "Duplicate email"}
        )
    return {"message": "User created"}

@app.get("/admin/users/{user_id}")
async def get_user(user_id: int, current_user: User = Depends(get_admin_user)):
    if not current_user.is_admin:
        raise HTTPException(
            status_code=403,
            detail="You do not have admin access"
        )
```

### Custom Exception Handlers

Override default exception handlers:

```python
from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse

class UnicornException(Exception):
    def __init__(self, name: str):
        self.name = name

app = FastAPI()

@app.exception_handler(UnicornException)
async def unicorn_exception_handler(request: Request, exc: UnicornException):
    return JSONResponse(
        status_code=418,
        content={"message": f"Oops! {exc.name} did something wrong"}
    )

@app.get("/unicorns/{name}")
async def read_unicorn(name: str):
    if name == "yolo":
        raise UnicornException(name=name)
    return {"unicorn_name": name}
```

### Override Default Validation Errors

Customize 422 validation error responses:

```python
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse

@app.exception_handler(RequestValidationError)
async def validation_exception_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content={
            "error": "Validation Error",
            "details": exc.errors(),
            "body": exc.body
        }
    )
```

### Override 404 Handler

```python
@app.exception_handler(404)
async def not_found_handler(request: Request, exc):
    return JSONResponse(
        status_code=404,
        content={
            "error": "Resource not found",
            "path": str(request.url)
        }
    )
```

### Global Exception Handler

```python
@app.exception_handler(Exception)
async def global_exception_handler(request: Request, exc: Exception):
    return JSONResponse(
        status_code=500,
        content={"error": "Internal server error", "detail": str(exc)}
    )
```

